mapper.select:
SELECT COUNT(*) FROM biz_spider_data
WHERE DATE(record_date) = CURDATE()

  AND branch_id = #{branchId}

SELECT COUNT(*) FROM biz_spider_data
WHERE DATE(record_date) = CURDATE() AND is_abnormal = 1

  AND branch_id = #{branchId}

SELECT COUNT(*) FROM biz_spider_data
WHERE DATE(record_date) = CURDATE() AND is_abnormal = 0

  AND branch_id = #{branchId}

SELECT DATE_FORMAT(DATE(record_date), '%m-%d') AS `date`, COALESCE(SUM(consultation_count), 0) AS consultation, SUM(CASE WHEN is_abnormal = 1 THEN 1 ELSE 0 END) AS abnormalCount FROM biz_spider_data WHERE record_date >= DATE_SUB(CURDATE(), INTERVAL 7 DAY)
AND branch_id = #{branchId}
GROUP BY DATE(record_date), DATE_FORMAT(DATE(record_date), '%m-%d') ORDER BY DATE(record_date) ASC

SELECT sd.id, sd.shop_id AS shopId, sd.response_rate_3m AS responseRate, sd.consultation_count AS consultationCount, sd.sales_amount AS salesAmount, sd.record_date AS recordDate, sd.create_time AS uploadTime FROM biz_spider_data sd WHERE sd.is_abnormal = 1
AND sd.branch_id = #{branchId}
ORDER BY sd.create_time DESC LIMIT 5
